        if (!empty($this->dateUpdated)) {
            $json['date_updated']                                =
                DateTimeHelper::toRfc3339DateTime(
                    $this->dateUpdated['value']
                );
        }
        if (!empty($this->apnCredentialSid)) {
            $json['apn_credential_sid']                          = $this->apnCredentialSid['value'];
        }
        if (!empty($this->gcmCredentialSid)) {
            $json['gcm_credential_sid']                          = $this->gcmCredentialSid['value'];
        }
        if (!empty($this->fcmCredentialSid)) {
            $json['fcm_credential_sid']                          = $this->fcmCredentialSid['value'];
        }
        if (!empty($this->messagingServiceSid)) {
            $json['messaging_service_sid']                       = $this->messagingServiceSid['value'];
        }
        if (!empty($this->facebookMessengerPageId)) {
            $json['facebook_messenger_page_id']                  = $this->facebookMessengerPageId['value'];
        }
        if (!empty($this->defaultApnNotificationProtocolVersion)) {
            $json['default_apn_notification_protocol_version']   =
                $this->defaultApnNotificationProtocolVersion['value'];
        }
        if (!empty($this->defaultGcmNotificationProtocolVersion)) {
            $json['default_gcm_notification_protocol_version']   =
                $this->defaultGcmNotificationProtocolVersion['value'];
        }
        if (!empty($this->defaultFcmNotificationProtocolVersion)) {
            $json['default_fcm_notification_protocol_version']   =
                $this->defaultFcmNotificationProtocolVersion['value'];
        }
        if (!empty($this->logEnabled)) {
            $json['log_enabled']                                 = $this->logEnabled['value'];
        }
        if (!empty($this->url)) {
            $json['url']                                         = $this->url['value'];
        }
        if (!empty($this->links)) {
            $json['links']                                       = $this->links['value'];
        }
        if (!empty($this->alexaSkillId)) {
            $json['alexa_skill_id']                              = $this->alexaSkillId['value'];
        }
        if (!empty($this->defaultAlexaNotificationProtocolVersion)) {
            $json['default_alexa_notification_protocol_version'] =
                $this->defaultAlexaNotificationProtocolVersion['value'];
        }
        if (!empty($this->deliveryCallbackUrl)) {
            $json['delivery_callback_url']                       = $this->deliveryCallbackUrl['value'];
        }
        if (!empty($this->deliveryCallbackEnabled)) {
            $json['delivery_callback_enabled']                   = $this->deliveryCallbackEnabled['value'];
        }
        $json = array_merge($json, $this->additionalProperties);

        return (!$asArrayWhenEmpty && empty($json)) ? new stdClass() : $json;
    }
}
